import{H as e,R as t,U as n,V as r,et as i,j as a}from"./chunks/framework.C_EfTa_6.js";var o=JSON.parse(`{"title":"多卡推理","description":"","frontmatter":{"title":"多卡推理","order":25},"headers":[],"relativePath":"ai/compute/deploy/multi-gpu.md","filePath":"ai/compute/deploy/multi-gpu.md"}`),s={name:`ai/compute/deploy/multi-gpu.md`},c={class:`MathJax`,jax:`SVG`,style:{direction:`ltr`,position:`relative`}},l={style:{overflow:`visible`,"min-height":`1px`,"min-width":`1px`,"vertical-align":`-0.025ex`},xmlns:`http://www.w3.org/2000/svg`,width:`1.179ex`,height:`1.595ex`,role:`img`,focusable:`false`,viewBox:`0 -694 521 705`,"aria-hidden":`true`};function u(a,o,s,u,d,f){return i(),r(`div`,null,[o[4]||=e(`<h1 id="多卡推理" tabindex="-1">多卡推理 <a class="header-anchor" href="#多卡推理" aria-label="Permalink to “多卡推理”">​</a></h1><p>当单卡显存放不下模型时，多 GPU 并行是唯一的出路。但并行策略选错，多卡可能跑得比单卡还慢——通信开销吃掉计算收益。理解每种并行策略的通信模式和硬件前提，是做对选型的关键。</p><h2 id="三种并行策略" tabindex="-1">三种并行策略 <a class="header-anchor" href="#三种并行策略" aria-label="Permalink to “三种并行策略”">​</a></h2><p>多 GPU 推理有三种基本并行方式，按通信频率从低到高排列：</p><p><strong>数据并行（DP）</strong>：每张卡持有完整模型副本，各自处理不同请求，卡间完全不需要通信。吞吐量线性增长，但单卡必须能装下完整模型。这是最简单的&quot;多卡&quot;方案——如果能用 DP，就不要用更复杂的策略。</p><p><strong>流水线并行（PP）</strong>：将模型按层切分——GPU 0 持有 1-16 层，GPU 1 持有 17-32 层。数据像流水线一样滚动，卡间只在层边界传递一次激活值。通信量极小，PCIe 3.0/4.0 完全够用。代价是存在&quot;气泡&quot;——前端 GPU 计算时后端 GPU 空闲等待。</p><p><strong>张量并行（TP）</strong>：将每层权重矩阵切分到多张 GPU，层内计算需要 AllReduce 同步。一个 32 层的模型，每生成一个 token，卡间就要进行 64 次通信。通信频率极高——必须有 NVLink（600 GB/s+）支撑，纯 PCIe 下 TP 通信延迟可能远超计算时间。</p><p>三者的核心差异：</p><table tabindex="0"><thead><tr><th>维度</th><th>DP</th><th>PP</th><th>TP</th></tr></thead><tbody><tr><td>通信频率</td><td>无</td><td>极低（层边界一次）</td><td>极高（每层 2 次）</td></tr><tr><td>带宽要求</td><td>无</td><td>PCIe 3.0 即可</td><td>必须 NVLink</td></tr><tr><td>能否&quot;凑显存&quot;</td><td>不能（单卡须装全量）</td><td>能（按层切分）</td><td>能（按矩阵切分）</td></tr><tr><td>降低单请求延迟</td><td>不能</td><td>不能（甚至略增）</td><td>能（多卡合力算一层）</td></tr><tr><td>提升并发吞吐</td><td>能（QPS 线性增长）</td><td>能（配合 micro-batch）</td><td>较弱</td></tr></tbody></table><h2 id="通信硬件-nvlink-vs-pcie" tabindex="-1">通信硬件：NVLink vs PCIe <a class="header-anchor" href="#通信硬件-nvlink-vs-pcie" aria-label="Permalink to “通信硬件：NVLink vs PCIe”">​</a></h2><p>NVLink 是 NVIDIA 的卡间直连技术，Ampere 代（3090、A6000 等）提供 112.5 GB/s 双向带宽。PCIe 4.0 x16 单向带宽仅 31.5 GB/s，约为 NVLink 的 1/4。TP 每层触发两次 AllReduce，NVLink 下通信耗时占总时间 &lt; 5%，PCIe 下可能 &gt; 50%。完整的 NVLink 兼容性参考见 <a href="./hardware">GPU 硬件</a>。</p><p>不具备 NVLink 的卡（RTX 4090、3080 等）多卡通信只能走 PCIe，优化方向：</p><p>开启 PCIe P2P：数据直接在 PCIe 总线上跨卡传输（GPU A → PCIe Switch → GPU B），不经系统内存中转。检查 <code>nvidia-smi topo -m</code>——PIX/PXB 表示 P2P 已生效，SYS 表示仍在走 CPU 中转，需检查 BIOS ACS 设置。</p><p>NCCL 参数调优：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NCCL_P2P_DISABLE</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#62687b;--shiki-dark:#818e99;">        # 强制开启 P2P</span></span>
<span class="line"><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NCCL_ALGO</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Tree,Ring       </span><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># 选择适合 PCIe 拓扑的算法</span></span>
<span class="line"><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> NCCL_BUFFSIZE</span><span style="--shiki-light:#c62739;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8388608</span><span style="--shiki-light:#62687b;--shiki-dark:#818e99;">     # 增大缓冲池，减少小包传输开销</span></span></code></pre></div><p>物理拓扑优化：确保所有 GPU 插在同一 NUMA 节点的 PCIe 插槽上，跨 NUMA 通信带宽减半、延迟翻倍。使用 PCIe Switch 扩展板可以让 GPU 间通信在 Switch 芯片内部转发，不经 CPU。</p><h2 id="本地部署的并行策略" tabindex="-1">本地部署的并行策略 <a class="header-anchor" href="#本地部署的并行策略" aria-label="Permalink to “本地部署的并行策略”">​</a></h2><p><strong>单卡能装下模型时</strong>——不需要 TP/PP。用多卡跑 DP 多实例，前面挂负载均衡，获得最高 QPS。这是最简单、最高效的方案。</p><p><strong>单卡装不下、有 NVLink 时</strong>——用 TP=2 拆分模型。NVLink 带宽充裕，通信开销可忽略，推理延迟接近单卡的 1/2。双卡 3090 + NVLink 桥是本地跑 70B 模型的最优方案。</p><p><strong>单卡装不下、无 NVLink 时</strong>——优先用 PP（流水线并行），将模型按层切分到不同卡上。PP 的通信量极小，PCIe 完全够用。避免在纯 PCIe 环境下使用高数位 TP——你会发现 GPU 绝大多数时间在挂起等待数据传输。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># SGLang: TP=2（有 NVLink 场景）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sglang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Qwen/Qwen3.6-72B-Instruct-AWQ</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># SGLang: PP=2（无 NVLink 场景，按层切分）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sglang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Qwen/Qwen3.6-72B-Instruct</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># SGLang: TP=2 + PP=2 混合（4 GPU）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sglang</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Qwen/Qwen3.6-72B</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --pp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># vLLM: DP 多实例（单卡能装下，追求高吞吐）</span></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># 在每个 GPU 上分别启动一个服务实例，前面用 Nginx 负载均衡</span></span></code></pre></div><h2 id="专家并行" tabindex="-1">专家并行 <a class="header-anchor" href="#专家并行" aria-label="Permalink to “专家并行”">​</a></h2><p>MoE（Mixture of Experts）架构的模型——如 DeepSeek-V3、Mixtral 8x7B、Qwen2.5-MoE——与传统 Dense 模型有根本区别：每个 Transformer 层的 FFN 被替换为多个并行的&quot;专家&quot;子网络，每个 token 只激活其中少数几个（通常 top-2）。参数量巨大（DeepSeek-V3 达 671B）但每次前向传播的计算量只对应激活参数（约 37B）。</p><p>专家并行（EP）将不同的 expert 分配到不同 GPU。每个 MoE 层的处理流程：Token 到达 → 门控网络（Router）计算每个 expert 的匹配分数 → 取 top-k expert（k=2） → 通过 All-to-All 通信将 token 分发到对应 expert 所在的 GPU → 各 GPU 计算自己负责的 expert → All-to-All 通信将结果传回 → 加权求和输出。</p>`,24),t(`p`,null,[o[2]||=n(`EP 的通信模式与 TP 有本质区别。TP 需要每层两次 AllReduce——所有 GPU 之间进行密集全量同步。EP 的 All-to-All 只发生在 token 路由时：每个 GPU 只发送/接收自己那部分 token 到激活的 expert 所在的 GPU。通信量与激活 expert 数成正比而非模型总层数——一个 token 在 60 层 MoE 模型中只触发 MoE 层（约每两层一次）的路由通信，且每次只与 `,-1),t(`mjx-container`,c,[(i(),r(`svg`,l,[...o[0]||=[t(`g`,{stroke:`currentColor`,fill:`currentColor`,"stroke-width":`0`,transform:`scale(1,-1)`},[t(`g`,{"data-mml-node":`math`},[t(`g`,{"data-mml-node":`mi`},[t(`path`,{"data-c":`1D458`,d:`M121 647Q121 657 125 670T137 683Q138 683 209 688T282 694Q294 694 294 686Q294 679 244 477Q194 279 194 272Q213 282 223 291Q247 309 292 354T362 415Q402 442 438 442Q468 442 485 423T503 369Q503 344 496 327T477 302T456 291T438 288Q418 288 406 299T394 328Q394 353 410 369T442 390L458 393Q446 405 434 405H430Q398 402 367 380T294 316T228 255Q230 254 243 252T267 246T293 238T320 224T342 206T359 180T365 147Q365 130 360 106T354 66Q354 26 381 26Q429 26 459 145Q461 153 479 153H483Q499 153 499 144Q499 139 496 130Q455 -11 378 -11Q333 -11 305 15T277 90Q277 108 280 121T283 145Q283 167 269 183T234 206T200 217T182 220H180Q168 178 159 139T145 81T136 44T129 20T122 7T111 -2Q98 -11 83 -11Q66 -11 57 -1T48 16Q48 26 85 176T158 471L195 616Q196 629 188 632T149 637H144Q134 637 131 637T124 640T121 647Z`,style:{"stroke-width":`3`}})])])],-1)]])),o[1]||=t(`mjx-assistive-mml`,{unselectable:`on`,display:`inline`,style:{top:`0px`,left:`0px`,clip:`rect(1px, 1px, 1px, 1px)`,"-webkit-touch-callout":`none`,"-webkit-user-select":`none`,"-khtml-user-select":`none`,"-moz-user-select":`none`,"-ms-user-select":`none`,"user-select":`none`,position:`absolute`,padding:`1px 0px 0px 0px`,border:`0px`,display:`block`,width:`auto`,overflow:`hidden`}},[t(`math`,{xmlns:`http://www.w3.org/1998/Math/MathML`},[t(`mi`,null,`k`)])],-1)]),o[3]||=n(` 个 expert 通信。`,-1)]),o[5]||=e(`<p>这使 EP 对 PCIe 环境的耐受度远超 TP。本地无 NVLink 的多卡平台跑 MoE 模型时，EP 的通信开销可控——不会像 TP 那样 GPU 绝大部分时间在等待 PCIe 传输。Mixtral 8x7B 在 2 张 3090 PCIe 直连下使用 EP，推理速度接近单卡的两倍；而同样的硬件跑 Dense 70B 模型用 TP=2，吞吐量可能比单卡还低。</p><p>EP 与 TP/PP 可以混合使用。DeepSeek-V3 的训练和推理使用了 EP + TP + PP 的组合：节点内 NVLink 互联的 GPU 之间用 TP 处理 Attention 层和 Shared Expert（每个 token 必算），跨节点用 EP 分发 Routed Expert，PP 处理流水线层级切分。本地小规模部署通常只需要 EP 或 EP + 小规模 PP。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># vLLM: MoE 模型自动启用 EP</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vllm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> deepseek-ai/DeepSeek-V3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tensor-parallel-size</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># 对于 MoE 模型，vLLM 会自动将 expert 分配到各 GPU</span></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># 可以通过 --max-num-seqs 控制并发请求数来间接影响 EP 效率</span></span></code></pre></div><p>MoE 模型的 CPU+GPU 混合推理同样遵循&quot;Attention 优先放 GPU&quot;原则——MoE 层中的 Attention 和 Shared Expert（如果存在）是每个 token 的必经之路，必须放 GPU。Routed Expert 可以部分卸载到 CPU——每个 token 只激活其中 2 个，PCIe 传输开销有限。</p><h2 id="异构显存与非对称多卡" tabindex="-1">异构显存与非对称多卡 <a class="header-anchor" href="#异构显存与非对称多卡" aria-label="Permalink to “异构显存与非对称多卡”">​</a></h2><p>本地常见的硬件组合是一张 32G/48G 主卡配几张 16G 副卡——捡二手硬件时很难凑齐同规格。这种非对称组合能用，但用对方式和用错方式的体验天差地别。</p><p>&quot;大卡+小卡&quot;的核心优势是单卡独立运行能力。32G 卡可以单卡装下 32B INT4 模型完整运行——完全不需要跨卡通信，延迟最低、速度最快。同等条件下全 16G 卡必须至少两张做 PP 才能跑同规模模型。此外 PP 允许非对称层切分——60 层的模型，32G 卡分配 40 层，16G 卡分配 20 层，可以最大化总显存利用率。</p><p>但在张量并行（TP）中，木桶效应是致命问题。主流框架（vLLM、SGLang）的 TP 要求每张卡分配等量的权重切片——32G 卡被迫当 16G 用，富余的 16G 显存直接浪费。更糟的是大卡通常伴随更高的算力和带宽，AllReduce 同步时快卡必须等慢卡——32G 卡的计算单元频繁空转，整机吞吐被 16G 卡拉低。TP 还要求卡数是 2 的幂次（2、4、8），1 张 32G + 2 张 16G 的 3 卡组合很多框架无法开启 TP=3。</p><p>最佳实践不是让大卡和小卡挤在同一个并行组里，而是做任务隔离：</p><p>方案 A（推荐，省心）：32G 卡单独跑一个 vLLM/SGLang 实例服务主力 LLM；16G 卡单独跑另一个实例服务 Embedding、RAG 向量检索或轻量 Agent。各管各的，互不拖累。</p><p>方案 B（极客，llama.cpp 异构切分）：用 llama.cpp 的层映射功能，手动指定不同卡加载不同层数——32G 加载 35 层，16G 加载 15 层。前提是使用 PP 模式的层切分而非 TP，且接受单请求延迟偏高的代价。</p><h2 id="pp-与投机解码的框架兼容性" tabindex="-1">PP 与投机解码的框架兼容性 <a class="header-anchor" href="#pp-与投机解码的框架兼容性" aria-label="Permalink to “PP 与投机解码的框架兼容性”">​</a></h2><p>投机解码和流水线并行在概念上可以叠加——PP 解决显存问题，投机解码解决速度问题。但框架兼容性有差异：</p><p>vLLM 和 SGLang 目前不支持 PP 与投机解码同时开启。投机解码在这些框架中只能配合 TP 使用——所以如果你的多卡方案选择了 PP，就无法在同一实例中使用投机采样。</p><p>llama.cpp 原生支持两者叠加——模型按层切分到多卡/CPU 的同时可以挂载 draft model 做投机解码。需要为 draft model 预留 1-2GB 显存空间。</p><p>MTP（Multi-Token Prediction）是绕过这个限制的替代方案。Qwen 2.5 等模型内置了多 Token 预测头——模型自身就能一次预测多个 token，不需要额外的 draft model。主模型用 PP 拆分的同时，MTP 投机自动生效，既省显存又免去框架兼容性问题：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># llama.cpp: PP层切分 + draft model 投机（同时启用）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">llama-cli</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen3.6-32b-Q4_K_M.gguf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qwen3.6-0.5b-Q4_K_M.gguf</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\ </span><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"> # draft model</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">  -ngl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 20</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --draft-max</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 16</span><span style="--shiki-light:#62687b;--shiki-dark:#818e99;">           # 主模型 GPU 层数 + 投机深度</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#62687b;--shiki-dark:#818e99;"># vLLM: TP + 投机（PP 不兼容投机解码）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vllm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> serve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Qwen/Qwen3.6-32B</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 2</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --speculative-model</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Qwen/Qwen3.6-0.5B</span></span></code></pre></div><h2 id="选型决策树" tabindex="-1">选型决策树 <a class="header-anchor" href="#选型决策树" aria-label="Permalink to “选型决策树”">​</a></h2><p>单卡能装下完整量化模型 → DP 多实例（零通信，最高吞吐）。单卡装不下、节点内有 NVLink → TP 优先（低延迟）+ MTP/投机解码。单卡装不下、节点内无 NVLink → PP 优先（低带宽容忍度）+ MTP（模型支持时）；如果模型不支持 MTP 则需要 llama.cpp 才能同时启用 PP + 投机解码。异构显存（大小卡混插）→ 任务隔离优先，不要塞进同一 TP 组。MoE 模型 → EP 优先（All-to-All 通信对 PCIe 友好），可叠加小规模 PP 拆分 attention+shared expert 与 routed expert。大规模集群（千卡以上） → DP + TP + PP 3D 并行——个人本地环境不需要。</p><p>EP 解决的是 MoE 模型的切分方式选择问题，MTP 解决的是 Decode 速度问题——两者解决不同维度，可以叠加使用。完整的并行策略与技术组合方案见<a href="./optimization">推理优化</a>。</p>`,20)])}var d=a(s,[[`render`,u]]);export{o as __pageData,d as default};